// Energy optimization algorithm
const demand = $fromAI('demand', 'Energy demand in kWh', 'number');
const renewable = $fromAI('renewable', 'Available renewable energy in kWh', 'number');
const efficiency = Math.min(renewable / demand * 100, 100);
return { efficiency, surplus: Math.max(renewable - demand, 0) };

